const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Security middleware
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      frameAncestors: ["'none'"] // Prevent clickjacking
    }
  },
  // Prevent IE from sniffing MIME types
  xContentTypeOptions: true,
  // Prevent Chrome from downloading potentially dangerous files
  xDownloadOptions: true,
  // Prevent framing of the page
  xFrameOptions: true,
  // Prevent XSS attacks
  xXssProtection: true
}));

// Rate limiting to prevent abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true, // Return rate limit info in the RateLimit-* headers
  legacyHeaders: false, // Disable the X-RateLimit-* headers
});

// Apply rate limiter to all requests
app.use(limiter);

// Parse JSON bodies
app.use(express.json({
  limit: '10kb' // Prevent large payload attacks
}));

// Validate content type
app.use((req, res, next) => {
  // If request has a body, ensure proper content type
  if (req.method !== 'GET' && req.method !== 'HEAD' && req.method !== 'OPTIONS') {
    const contentType = req.get('content-type');
    if (contentType && !contentType.includes('application/json')) {
      return res.status(415).json({
        error: 'Unsupported Media Type',
        message: 'Content-Type must be application/json'
      });
    }
  }
  next();
});

// Health check endpoint
app.get('/health', (req, res) => {
  try {
    // Validate query parameters if any
    if (Object.keys(req.query).length > 0) {
      return res.status(400).json({
        error: 'Invalid request',
        message: 'Health check endpoint does not accept query parameters'
      });
    }

    res.json({ status: 'ok', timestamp: new Date().toISOString() });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({
      error: 'Internal server error',
      message: 'Health check failed'
    });
  }
});

// Users endpoint
app.get('/users', (req, res) => {
  try {
    // Validate query parameters
    const { limit, offset } = req.query;

    // Input validation
    if (limit !== undefined) {
      const limitNum = parseInt(limit, 10);
      if (isNaN(limitNum) || limitNum < 1 || limitNum > 100) {
        return res.status(400).json({
          error: 'Invalid parameter',
          message: 'Limit must be a number between 1 and 100'
        });
      }
    }

    if (offset !== undefined) {
      const offsetNum = parseInt(offset, 10);
      if (isNaN(offsetNum) || offsetNum < 0) {
        return res.status(400).json({
          error: 'Invalid parameter',
          message: 'Offset must be a non-negative number'
        });
      }
    }

    // In a real application, this data would come from a database
    // with proper sanitization
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Apply pagination if requested
    let result = users;
    if (limit !== undefined || offset !== undefined) {
      const limitNum = parseInt(limit, 10) || users.length;
      const offsetNum = parseInt(offset, 10) || 0;
      result = users.slice(offsetNum, offsetNum + limitNum);
    }

    res.json(result);
  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({
      error: 'Internal server error',
      message: 'Failed to retrieve users'
    });
  }
});

// 404 handler for unknown routes
app.use((req, res) => {
  res.status(404).json({
    error: 'Not found',
    message: `Route ${req.method} ${req.url} not found`
  });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Uncaught error:', error);

  // Handle specific error types
  if (error.name === 'SyntaxError' && error.status === 400) {
    return res.status(400).json({
      error: 'Bad Request',
      message: 'Invalid JSON in request body'
    });
  }

  // Default to generic error message
  res.status(500).json({
    error: 'Internal server error',
    message: 'An unexpected error occurred'
  });
});

const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Environment: ${process.env.NODE_ENV || 'development'}`);
});

// Handle graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received, shutting down gracefully');
  server.close(() => {
    console.log('Process terminated');
  });
});

process.on('SIGINT', () => {
  console.log('SIGINT received, shutting down gracefully');
  server.close(() => {
    console.log('Process terminated');
  });
});

module.exports = app;

