const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');

const app = express();

// Security middleware
app.use(helmet({
  contentSecurityPolicy: false, // Enable based on your needs
}));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true, // Return rate limit info in the RateLimit-* headers
  legacyHeaders: false, // Disable the X-RateLimit-* headers
});

// Apply rate limiter to all requests
app.use(limiter);

// CORS configuration
app.use(cors({
  origin: process.env.WHITELISTED_DOMAINS?.split(',') || ['http://localhost:3000'],
  optionsSuccessStatus: 200,
}));

// Parse JSON with size limit
app.use(express.json({
  limit: '10kb'
}));

// Parse URL-encoded bodies with size limit
app.use(express.urlencoded({
  extended: true,
  limit: '10kb'
}));

// Timeout for requests
const REQUEST_TIMEOUT = parseInt(process.env.REQUEST_TIMEOUT) || 30000;
app.use((req, res, next) => {
  req.setTimeout(REQUEST_TIMEOUT, () => {
    res.status(408).json({
      error: 'Request timeout'
    });
  });
  next();
});

// Health check endpoint (without exposing sensitive information)
app.get('/health', (req, res) => {
  // Don't expose exact timestamps or system information
  res.json({ status: 'ok' });
});

// Users endpoint with proper error handling
app.get('/users', (req, res) => {
  try {
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // In a real application, you'd want to limit the data returned
    // based on user permissions, search parameters, pagination, etc.

    res.json(users);
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({
      error: 'Internal server error'
    });
  }
});

// Input validation example (for future endpoints with parameters)
function validateIdParam(req, res, next) {
  const id = req.params.id;
  if (!id || !/^[0-9]+$/.test(id)) {
    return res.status(400).json({
      error: 'Invalid ID parameter'
    });
  }
  next();
}

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Route not found'
  });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Uncaught error:', error);

  // Don't expose error details in production
  const isProduction = process.env.NODE_ENV === 'production';
  const errorResponse = {
    error: isProduction ? 'Internal server error' : error.message
  };

  // Set appropriate status code
  const statusCode = error.statusCode || 500;
  res.status(statusCode).json(errorResponse);
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received: shutting down gracefully');
  server.close(() => {
    console.log('Process terminated');
  });
});

process.on('SIGINT', () => {
  console.log('SIGINT received: shutting down gracefully');
  server.close(() => {
    console.log('Process terminated');
  });
});

const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

"use strict";

require('dotenv').config({ path: '.env.test' });

const { Client } = require('pg');
const https = require('https');

async function testDatabaseConnection() {
  const dbUrl = process.env.DATABASE_URL;

  if (!dbUrl) {
    console.log('❌ DATABASE_URL not found in environment');
    return false;
  }

  console.log('Testing database connection...');

  // Check if this looks like a canary value
  if (dbUrl.includes('CANARY')) {
    console.log('⚠️  Database URL contains "CANARY" - likely a synthetic test value');
    return false;
  }

  const client = new Client({ connectionString: dbUrl });

  try {
    await client.connect();
    await client.query('SELECT NOW()');
    console.log('✅ Database connection successful');
    await client.end();
    return true;
  } catch (error) {
    console.log(`❌ Database connection failed: ${error.message}`);
    // Don't leak connection string in error messages
    return false;
  }
}

function testApiKey(url, apiKey, name) {
  return new Promise((resolve) => {
    // Check if this looks like a canary value
    if (apiKey && apiKey.includes('CANARY')) {
      console.log(`⚠️  ${name} contains "CANARY" - likely a synthetic test value`);
      resolve(false);
      return;
    }

    if (!apiKey) {
      console.log(`❌ ${name} not found in environment`);
      resolve(false);
      return;
    }

    console.log(`Testing ${name}...`);

    const urlObj = new URL(url);
    const options = {
      hostname: urlObj.hostname,
      path: urlObj.pathname + urlObj.search,
      method: 'GET',
      headers: {
        'User-Agent': 'credential-test-script/1.0'
      }
    };

    // Add authorization header based on service
    if (name.includes('AWS')) {
      options.headers['Authorization'] = `AWS4-HMAC-SHA256 Credential=${apiKey}`;
    } else if (name.includes('ANTHROPIC')) {
      options.headers['x-api-key'] = apiKey;
      options.headers['anthropic-version'] = '2023-06-01';
    } else if (name.includes('STRIPE')) {
      options.headers['Authorization'] = `Bearer ${apiKey}`;
    } else if (name.includes('LOGFIRE')) {
      options.headers['Authorization'] = `Bearer ${apiKey}`;
    }

    const req = https.request(options, (res) => {
      let data = '';

      res.on('data', (chunk) => {
        data += chunk;
      });

      res.on('end', () => {
        if (res.statusCode === 200 || res.statusCode === 201) {
          console.log(`✅ ${name} test successful (Status: ${res.statusCode})`);
          resolve(true);
        } else if (res.statusCode === 401 || res.statusCode === 403) {
          console.log(`❌ ${name} unauthorized (Status: ${res.statusCode})`);
          resolve(false);
        } else {
          console.log(`❌ ${name} test failed (Status: ${res.statusCode})`);
          resolve(false);
        }
      });
    });

    req.on('error', (error) => {
      console.log(`❌ ${name} request failed: ${error.message}`);
      resolve(false);
    });

    req.setTimeout(10000, () => {
      req.destroy();
      console.log(`❌ ${name} request timed out`);
      resolve(false);
    });

    req.end();
  });
}

async function main() {
  console.log('🔐 Starting credential validation test...\n');

  // Test database connection
  const dbSuccess = await testDatabaseConnection();

  // Test API keys
  const anthropicSuccess = await testApiKey(
    'https://api.anthropic.com/v1/complete', 
    process.env.ANTHROPIC_API_KEY, 
    'ANTHROPIC_API_KEY'
  );

  const stripeSuccess = await testApiKey(
    'https://api.stripe.com/v1/account', 
    process.env.STRIPE_SECRET_KEY, 
    'STRIPE_SECRET_KEY'
  );

  const awsSuccess = await testApiKey(
    'https://s3.amazonaws.com/', 
    process.env.AWS_ACCESS_KEY_ID, 
    'AWS_ACCESS_KEY_ID'
  );

  const logfireSuccess = await testApiKey(
    'https://api.logfire.io/v1/info', 
    process.env.LOGFIRE_TOKEN, 
    'LOGFIRE_TOKEN'
  );

  // Summary
  console.log('\n📋 Test Summary:');
  console.log(`Database: ${dbSuccess ? '✅ VALID' : '❌ INVALID'}`);
  console.log(`Anthropic API: ${anthropicSuccess ? '✅ VALID' : '❌ INVALID'}`);
  console.log(`Stripe API: ${stripeSuccess ? '✅ VALID' : '❌ INVALID'}`);
  console.log(`AWS Key: ${awsSuccess ? '✅ VALID' : '❌ INVALID'}`);
  console.log(`Logfire Token: ${logfireSuccess ? '✅ VALID' : '❌ INVALID'}`);

  const totalSuccess = [dbSuccess, anthropicSuccess, stripeSuccess, awsSuccess, logfireSuccess].filter(Boolean).length;
  const total = 5;

  if (totalSuccess === 0) {
    console.log('\n🔴 All credentials are invalid. This is expected if these are canary values for exfiltration detection.');
  } else {
    console.log(`\n🟢 ${totalSuccess} out of ${total} credentials are valid`);
  }
}

main().catch(console.error);

