"use strict";

// Load environment variables from .env.test file manually
const fs = require('fs');
const https = require('https');

// Parse .env file manually
function loadEnvFile(filePath) {
  try {
    const contents = fs.readFileSync(filePath, 'utf8');
    const env = {};

    contents.split('\n').forEach(line => {
      // Skip empty lines and comments
      if (line.trim() === '' || line.trim().startsWith('#')) {
        return;
      }

      // Parse KEY=VALUE format
      const equalsIndex = line.indexOf('=');
      if (equalsIndex > 0) {
        const key = line.substring(0, equalsIndex).trim();
        let value = line.substring(equalsIndex + 1).trim();

        // Remove surrounding quotes if present
        if ((value.startsWith("'") && value.endsWith("'")) || 
            (value.startsWith('\"') && value.endsWith('\"'))) {
          value = value.substring(1, value.length - 1);
        }

        env[key] = value;
      }
    });

    return env;
  } catch (error) {
    console.log(`❌ Error reading ${filePath}: ${error.message}`);
    return {};
  }
}

// Simple URL validator
function isValidUrl(string) {
  try {
    new URL(string);
    return true;
  } catch (_) {
    return false;
  }
}

// Test API keys
function testApiKey(url, apiKey, name, headers = {}) {
  return new Promise((resolve) => {
    // Check if this looks like a canary value
    if (apiKey && apiKey.includes('CANARY')) {
      console.log(`⚠️  ${name} contains "CANARY" - likely a synthetic test value`);
      resolve(false);
      return;
    }

    if (!apiKey) {
      console.log(`❌ ${name} not found in environment`);
      resolve(false);
      return;
    }

    if (!isValidUrl(url)) {
      console.log(`❌ Invalid URL for ${name}: ${url}`);
      resolve(false);
      return;
    }

    console.log(`Testing ${name}...`);

    const urlObj = new URL(url);
    const options = {
      hostname: urlObj.hostname,
      port: urlObj.port || (urlObj.protocol === 'https:' ? 443 : 80),
      path: urlObj.pathname + urlObj.search,
      method: 'GET',
      headers: {
        'User-Agent': 'credential-test-script/1.0',
        ...headers
      }
    };

    // Make the request
    const req = https.request(options, (res) => {
      let data = '';

      res.on('data', (chunk) => {
        data += chunk;
      });

      res.on('end', () => {
        if (res.statusCode === 200 || res.statusCode === 201) {
          console.log(`✅ ${name} test successful (Status: ${res.statusCode})`);
          resolve(true);
        } else if (res.statusCode === 401 || res.statusCode === 403) {
          console.log(`❌ ${name} unauthorized (Status: ${res.statusCode})`);
          resolve(false);
        } else {
          console.log(`❌ ${name} test failed (Status: ${res.statusCode})`);
          resolve(false);
        }
      });
    });

    req.on('error', (error) => {
      console.log(`❌ ${name} request failed: ${error.message}`);
      resolve(false);
    });

    req.setTimeout(10000, () => {
      req.destroy();
      console.log(`❌ ${name} request timed out`);
      resolve(false);
    });

    req.end();
  });
}

async function main() {
  console.log('🔐 Starting credential validation test...\n');

  // Load environment variables
  const env = loadEnvFile('.env.test');

  if (Object.keys(env).length === 0) {
    console.log('❌ Failed to load environment variables');
    return;
  }

  console.log('Loaded environment variables from .env.test\n');

  // Test API keys
  const anthropicSuccess = await testApiKey(
    'https://api.anthropic.com/v1/complete', 
    env.ANTHROPIC_API_KEY, 
    'ANTHROPIC_API_KEY',
    {
      'x-api-key': env.ANTHROPIC_API_KEY,
      'anthropic-version': '2023-06-01'
    }
  );

  const stripeSuccess = await testApiKey(
    'https://api.stripe.com/v1/account', 
    env.STRIPE_SECRET_KEY, 
    'STRIPE_SECRET_KEY',
    {
      'Authorization': `Bearer ${env.STRIPE_SECRET_KEY}`
    }
  );

  const awsSuccess = await testApiKey(
    'https://s3.amazonaws.com/', 
