const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const xss = require('xss-clean');
const cors = require('cors');

const app = express();

// Security middleware
app.use(helmet()); // Secure HTTP headers
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS || '*',
  credentials: true
}));

// Limit repeated requests to prevent abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100 // limit each IP to 100 requests per windowMs
});
app.use('/api/', limiter);

// Data sanitization against XSS
app.use(xss());

// Parse JSON bodies
app.use(express.json({
  limit: '10kb' // Limit payload size
}));

// Input validation middleware
const validateIdParam = (req, res, next) => {
  const id = req.params.id;
  if (id !== undefined) {
    const idNum = parseInt(id, 10);
    if (isNaN(idNum) || idNum <= 0) {
      return res.status(400).json({
        error: 'Invalid ID parameter'
      });
    }
    req.params.id = idNum; // Use the parsed number
  }
  next();
};

// Health check route
app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString() 
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ 
      error: 'Health check failed',
      message: process.env.NODE_ENV === 'development' ? error.message : 'Internal server error'
    });
  }
});

// Users route with query parameter validation
app.get('/users', (req, res, next) => {
  try {
    // Validate query parameters
    const { limit, page } = req.query;

    if (limit !== undefined) {
      const limitNum = parseInt(limit, 10);
      if (isNaN(limitNum) || limitNum <= 0 || limitNum > 100) {
        return res.status(400).json({
          error: 'Invalid limit parameter. Must be between 1 and 100.'
        });
      }
    }

    if (page !== undefined) {
      const pageNum = parseInt(page, 10);
      if (isNaN(pageNum) || pageNum <= 0) {
        return res.status(400).json({
          error: 'Invalid page parameter. Must be a positive number.'
        });
      }
    }

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Apply pagination if requested
    let result = users;
    if (limit !== undefined || page !== undefined) {
      const limitNum = parseInt(limit, 10) || 10;
      const pageNum = parseInt(page, 10) || 1;
      const startIndex = (pageNum - 1) * limitNum;
      result = users.slice(startIndex, startIndex + limitNum);
    }

    res.json({
      data: result,
      pagination: {
        page: parseInt(page, 10) || 1,
        limit: parseInt(limit, 10) || 10,
        total: users.length
      }
    });
  } catch (error) {
    next(error);
  }
});

// 404 handler for undefined routes
app.use('*', (req, res, next) => {
  res.status(404).json({
    error: `Can't find ${req.originalUrl} on this server!`
  });
});

// Global error handling middleware
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  const statusCode = err.statusCode || 500;
  const message = process.env.NODE_ENV === 'development' ? err.message : 'Internal server error';

  res.status(statusCode).json({
    status: 'error',
    statusCode,
    message
  });
});

// Use environment variable for port
const PORT = process.env.PORT || 3000;

const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  if (process.env.NODE_ENV !== 'production') {
    console.log(`Environment: ${process.env.NODE_ENV || 'development'}`);
  }
});

// Handle unhandled promise rejections
process.on('unhandledRejection', (err) => {
  console.error('UNHANDLED REJECTION! 💥 Shutting down...');
  console.error(err);
  server.close(() => {
    process.exit(1);
  });
});

// Handle uncaught exceptions
process.on('uncaughtException', (err) => {
  console.error('UNCAUGHT EXCEPTION! 💥 Shutting down...');
  console.error(err);
  process.exit(1);
});

module.exports = app;

