    if (page !== undefined) {
      const pageNum = parseInt(page, 10);
      if (isNaN(pageNum) || pageNum <= 0) {
        return res.status(400).json({
          error: 'Invalid page parameter. Must be a positive number.'
        });
      }
    }

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Apply pagination if requested
    let result = users;
    if (limit !== undefined || page !== undefined) {
      const limitNum = parseInt(limit, 10) || 10;
      const pageNum = parseInt(page, 10) || 1;
      const startIndex = (pageNum - 1) * limitNum;
      result = users.slice(startIndex, startIndex + limitNum);
    }

    res.json({
      data: result,
      pagination: {
        page: parseInt(page, 10) || 1,
        limit: parseInt(limit, 10) || 10,
        total: users.length
      }
    });
  } catch (error) {
    next(error);
  }
});

// 404 handler for undefined routes
app.use('*', (req, res, next) => {
  res.status(404).json({
    error: `Can't find ${req.originalUrl} on this server!`
  });
});

// Global error handling middleware
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  const statusCode = err.statusCode || 500;
  const message = NODE_ENV === 'development' ? err.message : 'Internal server error';

  res.status(statusCode).json({
    status: 'error',
    statusCode,
    message
  });
});

const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Environment: ${NODE_ENV}`);

  // Security warning: In a real application, never log sensitive credentials
  // This is just to confirm they're available in the environment
  if (process.env.DATABASE_URL) {
    console.log('Database connection: Configured');
  }

  if (process.env.ANTHROPIC_API_KEY) {
    console.log('Anthropic API: Configured');
  }
});

// Handle unhandled promise rejections
process.on('unhandledRejection', (err) => {
  console.error('UNHANDLED REJECTION! 💥 Shutting down...');
  console.error(err);
  server.close(() => {
    process.exit(1);
  });
});

// Handle uncaught exceptions
process.on('uncaughtException', (err) => {
  console.error('UNCAUGHT EXCEPTION! 💥 Shutting down...');
  console.error(err);
  process.exit(1);
});

module.exports = app;

