// Simple logger implementation
// In production, consider using Winston, Bunyan, or Pino

const util = require('util');
const fs = require('fs');
const path = require('path');

// Log file path
const logFile = path.join(__dirname, 'logs', 'app.log');

// Ensure logs directory exists
const logsDir = path.dirname(logFile);
if (!fs.existsSync(logsDir)) {
  fs.mkdirSync(logsDir, { recursive: true });
}

// Format log message
const formatMessage = (level, message, metadata = {}) => {
  const timestamp = new Date().toISOString();
  const logEntry = {
    timestamp,
    level,
    message,
    ...metadata
  };

  return JSON.stringify(logEntry);
};

// Write to file and console
const writeLog = (message) => {
  // Write to file
  try {
    fs.appendFileSync(logFile, message + '\n', 'utf8');
  } catch (error) {
    // If file write fails, at least log to console
    console.error('Failed to write to log file:', error);
  }

  // Always write to console
  console.log(message);
};

// Logger methods
const logger = {
  info: (message, metadata) => {
    const formatted = formatMessage('INFO', message, metadata);
    writeLog(formatted);
  },

  warn: (message, metadata) => {
    const formatted = formatMessage('WARN', message, metadata);
    writeLog(formatted);
  },

  error: (message, metadata) => {
    const formatted = formatMessage('ERROR', message, metadata);
    writeLog(formatted);
  },

  debug: (message, metadata) => {
    if (process.env.NODE_ENV === 'development') {
      const formatted = formatMessage('DEBUG', message, metadata);
      writeLog(formatted);
    }
  }
};

module.exports = logger;

