"use strict";

const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('rate-limiter-flexible');
const { body, query, param, validationResult } = require('express-validator');
const winston = require('winston');

// Create Express app
const app = express();

// Set up logging
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  defaultMeta: { service: 'user-service' },
  transports: [
    // Write all logs with level `error` and below to `error.log`
    new winston.transports.File({ filename: 'error.log', level: 'error' }),
    // Write all logs with level `info` and below to `combined.log`
    new winston.transports.File({ filename: 'combined.log' }),
  ],
});

// If we're not in production, log to the console with the format: 'YYYY-MM-DD HH:MM:SS error: message'
if (process.env.NODE_ENV !== 'production') {
  logger.add(new winston.transports.Console({
    format: winston.format.combine(
      winston.format.colorize(),
      winston.format.simple()
    ),
  }));
}

// Security Middleware
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"]
    }
  },
  hidePoweredBy: true, // Removes X-Powered-By header
}));

// CORS Configuration
const allowedOrigins = process.env.ALLOWED_ORIGINS ? 
  process.env.ALLOWED_ORIGINS.split(',') : ['http://localhost:3000'];

app.use(cors({
  origin: function (origin, callback) {
    // Allow requests with no origin (like mobile apps, curl, etc.)
    if (!origin) return callback(null, true);
    if (allowedOrigins.indexOf(origin) === -1) {
      const msg = 'The CORS policy for this site does not allow access from the specified origin.';
      return callback(new Error(msg), false);
    }
    return callback(null, true);
  },
  credentials: true,
  optionsSuccessStatus: 200
}));

// Rate limiting
const limiter = new rateLimit.RateLimiterMemory({
  points: 100, // 100 requests
  duration: 60, // per minute
});

// Apply rate limiter to all requests
app.use((req, res, next) => {
  limiter.consume(req.ip)
    .then(() => {
      next();
    })
    .catch(() => {
      res.status(429).json({
        error: {
          message: 'Too Many Requests',
          code: 'TOO_MANY_REQUESTS'
        }
      });
    });
});

// Body parsing with size limits
app.use(express.json({
  limit: '10kb'
}));
app.use(express.urlencoded({
  extended: true,
  limit: '10kb'
}));

// Input validation middleware for users endpoint
const validateUserId = [
  param('id')
    .isInt({ min: 1 })
    .withMessage('User ID must be a positive integer')
    .toInt()
];

const validateUserQuery = [
  query('limit')
    .optional()
    .isInt({ min: 1, max: 100 })
    .withMessage('Limit must be an integer between 1 and 100')
    .toInt(),
  query('page')
    .optional()
    .isInt({ min: 1 })
    .withMessage('Page must be a positive integer')
    .toInt()
];

// Mock user data
const users = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob', email: 'bob@example.com' },
];

// Health check endpoint
app.get('/health', [
  query('full').optional().isBoolean().toBoolean()
], (req, res) => {
  // Check for validation errors
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({
      error: {
        message: 'Invalid request parameters',
        code: 'VALIDATION_ERROR',
        details: errors.array()
      }
    });
  }

  const healthData = {
    status: 'ok',
    timestamp: new Date().toISOString(),
    service: 'user-api'
  };

  // Full health check with additional info
  if (req.query.full) {
    healthData.details = {
      uptime: process.uptime(),
      memoryUsage: process.memoryUsage(),
      nodeVersion: process.version
    };
  }

  res.json(healthData);
});

// Get all users
app.get('/users', validateUserQuery, (req, res) => {
  // Check for validation errors
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    logger.warn('Validation error in /users', { errors: errors.array(), query: req.query });
    return res.status(400).json({
      error: {
        message: 'Invalid request parameters',
        code: 'VALIDATION_ERROR',
        details: errors.array()
      }
    });
  }

