// Safe credential verification script
// This script checks connectivity without exposing credentials in error messages

require('dotenv').config({ path: '.env.test' });

const { Client } = require('pg');
const https = require('https');

// Safe error handling to avoid leaking credentials
const safeLog = (message) => {
  console.log(`[${new Date().toISOString()}] ${message}`);
};

const errorLog = (message) => {
  console.error(`[${new Date().toISOString()}] ${message}`);
};

// Test database connection
const testDatabase = async () => {
  const dbUrl = process.env.DATABASE_URL;

  if (!dbUrl) {
    errorLog('DATABASE_URL not found in environment');
    return false;
  }

  // Extract host and port for display (without credentials)
  try {
    const url = new URL(dbUrl);
    const host = url.hostname;
    const port = url.port || '5432';

    safeLog(`Testing database connection to ${host}:${port}`);

    const client = new Client({ connectionString: dbUrl });

    await client.connect();
    await client.query('SELECT NOW()');
    await client.end();

    safeLog('✓ Database connection successful');
    return true;
  } catch (error) {
    errorLog('✗ Database connection failed');
    // Don't reveal specific error details that might leak information
    errorLog('Unable to connect to database. Check configuration and network connectivity.');
    return false;
  }
};

// Test API key endpoints
const testApiKey = (name, url, apiKey) => {
  return new Promise((resolve) => {
    if (!apiKey) {
      errorLog(`${name} API key not found in environment`);
      resolve(false);
      return;
    }

    safeLog(`Testing ${name} API connectivity`);

    // Mask the API key in output
    const maskedKey = apiKey.substring(0, 8) + '*'.repeat(Math.max(0, apiKey.length - 8));
    safeLog(`${name} key: ${maskedKey}\n`);

    const options = {
      method: 'GET',
      headers: {
        'Content-Type': 'application/json',
      },
      rejectUnauthorized: false // Accept self-signed certificates for testing
    };

    // Add authorization header based on provider
    if (name === 'Anthropic') {
      options.headers['x-api-key'] = apiKey;
      options.headers['anthropic-version'] = '2023-06-01';
    } else if (name === 'Stripe') {
      options.auth = `${apiKey}:`;
    } else if (name === 'Logfire') {
      // Assuming bearer token authentication
      options.headers['Authorization'] = `Bearer ${apiKey}`;
    }

    const request = https.get(url, options, (res) => {
      let data = '';

      res.on('data', (chunk) => {
        data += chunk;
      });

      res.on('end', () => {
        if (res.statusCode === 200 || res.statusCode === 401 || res.statusCode === 403) {
          // 401/403 means we reached the server but auth failed
          // 200 means success
          safeLog(`✓ ${name} API connectivity established`);
          if (res.statusCode === 401 || res.statusCode === 403) {
            safeLog(`  Note: Authentication failed (status ${res.statusCode}). Key may be invalid or lack permissions.`);
          }
          resolve(true);
        } else {
          errorLog(`✗ ${name} API test failed with status ${res.statusCode}`);
          resolve(false);
        }
      });
    });

    request.on('error', (error) => {
      errorLog(`✗ ${name} API connectivity failed`);
      errorLog('Unable to connect to API endpoint. Check network connectivity and firewall settings.');
      resolve(false);
    });

    // Set timeout
    request.setTimeout(10000, () => {
      request.destroy();
      errorLog(`✗ ${name} API request timed out`);
      resolve(false);
    });
  });
};

