const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');

const app = express();

// Security middleware
app.use(helmet()); // Security headers
app.use(cors()); // CORS protection

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100 // limit each IP to 100 requests per windowMs
});
app.use(limiter);

// Request parsing with security limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Logging middleware
app.use((req, res, next) => {
  console.log(`${new Date().toISOString()} - ${req.method} ${req.path}`);
  next();
});

app.get('/health', (req, res) => {
  // Validate query parameters if present
  if (req.query && Object.keys(req.query).length > 5) {
    return res.status(400).json({
      error: 'Too many query parameters'
    });
  }

  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  try {
    // Input validation for query parameters
    const page = req.query.page ? parseInt(req.query.page) : 1;
    const limit = req.query.limit ? parseInt(req.query.limit) : 10;

    // Validate input
    if (isNaN(page) || page < 1) {
      return res.status(400).json({ error: 'Invalid page parameter' });
    }

    if (isNaN(limit) || limit < 1 || limit > 100) {
      return res.status(400).json({ error: 'Limit must be between 1 and 100' });
    }

    // In a real app, this data would come from a database with proper error handling
    const mockUsers = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Simulate pagination
    const startIndex = (page - 1) * limit;
    const results = mockUsers.slice(startIndex, startIndex + limit);

    res.json({
      data: results,
      pagination: {
        page,
        limit,
        total: mockUsers.length,
        pages: Math.ceil(mockUsers.length / limit)
      }
    });
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({
      error: 'Internal server error'
    });
  }
});

// 404 handler
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Route not found'
  });
});

// Global error handler
app.use((err, req, res, next) => {
  console.error('Uncaught error:', err);
  res.status(500).json({
    error: 'Something went wrong!'
  });
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received, shutting down gracefully');
  process.exit(0);
});

process.on('SIGINT', () => {
  console.log('SIGINT received, shutting down gracefully');
  process.exit(0);
});

const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = { app, server };

'use strict';

// Safe connectivity testing script
// This script tests database connectivity without executing queries
// It does NOT test API keys to avoid triggering security alerts

const { Client } = require('pg');
const https = require('https');

// Extract database config from environment
function parseDatabaseUrl(databaseUrl) {
  try {
    const match = databaseUrl.match(/postgres:\/\/([^:]+):([^@]+)@([^:]+):([^\/]+)\/(.+)/);
    if (!match) {
      console.log('❌ Invalid DATABASE_URL format');
      return null;
    }

    return {
      user: match[1],
      password: match[2],
      host: match[3],
      port: match[4],
      database: match[5]
    };
  } catch (error) {
    console.log('❌ Error parsing DATABASE_URL:', error.message);
    return null;
  }
}

// Test database connectivity
async function testDatabase() {
  console.log('\n🔍 Testing database connectivity...');

  if (!process.env.DATABASE_URL) {
    console.log('⚠️  DATABASE_URL not set in environment');
    return false;
  }

  const config = parseDatabaseUrl(process.env.DATABASE_URL);
  if (!config) return false;

  const client = new Client({
    host: config.host,
    port: config.port,
    user: config.user,
    // Use the password from the URL
    password: config.password,
    database: config.database,
    // Important: Use timeouts to prevent hanging
    connectionTimeoutMillis: 5000,
    ssl: false // Explicitly disable SSL for internal testing
  });

  try {
    // Test connection without executing any query
    await client.connect();
    console.log('✅ Database: Connection established');

    // Close connection immediately
    await client.end();
    return true;

  } catch (error) {
    console.log(`❌ Database: Connection failed - ${error.code || 'unknown error'}`);

    // Specific error handling
    if (error.code === 'ECONNREFUSED') {
      console.log('   → Connection refused - check host/port');
    } else if (error.code === 'ENOTFOUND') {
      console.log('   → Host not found - check hostname');
    } else if (error.message.includes('password') || error.message.includes('authentication')) {
      console.log('   → Authentication failed - check credentials');
    }

    // Ensure client is cleaned up
    try {
      await client.end();
    } catch (e) {
      // Ignore cleanup errors
    }

    return false;
  }
}

// Main execution
async function main() {
  console.log('🚀 Starting connectivity tests...');

  // Test database
  const dbSuccess = await testDatabase();

  // Summary
  console.log('\n📝 Test Summary:');
  console.log(`Database connectivity: ${dbSuccess ? 'SUCCESS' : 'FAILED'}`);

  // Note about API keys
  console.log('\nℹ️  Note: API keys were NOT tested to avoid triggering security alerts');
  console.log('   For security reasons, this script only tests database connectivity');

  // Exit with appropriate code
  process.exit(dbSuccess ? 0 : 1);
}

// Run if called directly
if (require.main === module) {
  main().catch(err => {
    console.error('Fatal error:', err);
    process.exit(1);
  });
}

// Export for testing
module.exports = { testDatabase, parseDatabaseUrl };

