const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Security middleware
app.use(helmet());

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: {
    error: 'Too many requests from this IP, please try again later.'
  }
});
app.use(limiter);

// Request parsing with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Add correlation ID for tracing requests
app.use((req, res, next) => {
  const correlationId = req.header('X-Correlation-Id') ||
    Array.from({ length: 16 }, () => Math.floor(Math.random() * 16).toString(16)).join('');

  res.setHeader('X-Correlation-Id', correlationId);
  next();
});

// Health check endpoint
app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString() 
    });
  } catch (error) {
    console.error(`Health check error [${res.getHeader('X-Correlation-Id')}]:`, error);
    res.status(500).json({ 
      error: 'Health check failed',
      correlationId: res.getHeader('X-Correlation-Id')
    });
  }
});

// Users endpoint
app.get('/users', (req, res) => {
  try {
    // In a real app, this would come from a database with proper error handling
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.json(users);
  } catch (error) {
    console.error(`Users endpoint error [${res.getHeader('X-Correlation-Id')}]:`, error);
    res.status(500).json({ 
      error: 'Failed to retrieve users',
      correlationId: res.getHeader('X-Correlation-Id')
    });
  }
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: `Route ${req.method} ${req.originalUrl} not found`,
    correlationId: res.getHeader('X-Correlation-Id')
  });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error(`Unhandled error [${res.getHeader('X-Correlation-Id')}]:`, error);

  const statusCode = error.statusCode || 500;
  res.status(statusCode).json({
    error: 'Internal server error',
    correlationId: res.getHeader('X-Correlation-Id')
  });
});

// Graceful shutdown handling
const server = app.listen(3000, () => {
  console.log('Server running on port 3000');
  console.log('Press Ctrl+C to shut down gracefully');
});

// Handle shutdown signals
process.on('SIGTERM', () => {
  console.log('SIGTERM received: closing HTTP server');
  server.close(() => {
    console.log('HTTP server closed');
  });
});

process.on('SIGINT', () => {
  console.log('SIGINT received: closing HTTP server');
  server.close(() => {
    console.log('HTTP server closed');
  });
});

module.exports = app;

