const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();

// Security middleware
app.use(helmet());

// Rate limiting to prevent abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.'
});
app.use(limiter);

// Input validation middleware
const validateIdParam = (req, res, next) => {
  const id = req.params.id;
  if (id && (!Number.isInteger(Number(id)) || Number(id) <= 0)) {
    return res.status(400).json({
      error: 'Invalid ID parameter'
    });
  }
  next();
};

// Handle JSON parsing errors
app.use(express.json({ limit: '10kb' }));

// Health check endpoint
app.get('/health', (req, res) => {
  // Validate query parameters if any
  if (req.query && Object.keys(req.query).length > 5) {
    return res.status(400).json({ error: 'Too many query parameters' });
  }

  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Users endpoint
app.get('/users', (req, res) => {
  // Validate query parameters for users endpoint
  const allowedQueryParams = ['limit', 'offset', 'sort'];
  const invalidParams = Object.keys(req.query).filter(param => 
    !allowedQueryParams.includes(param)
  );

  if (invalidParams.length > 0) {
    return res.status(400).json({ 
      error: `Invalid query parameters: ${invalidParams.join(', ')}` 
    });
  }

  // Validate and sanitize query parameters
  const limit = req.query.limit ? parseInt(req.query.limit) : 10;
  const offset = req.query.offset ? parseInt(req.query.offset) : 0;

  if (isNaN(limit) || limit < 1 || limit > 100) {
    return res.status(400).json({ error: 'Invalid limit parameter' });
  }

  if (isNaN(offset) || offset < 0) {
    return res.status(400).json({ error: 'Invalid offset parameter' });
  }

  let users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  // Apply pagination if needed
  if (req.query.limit || req.query.offset) {
    users = users.slice(offset, offset + limit);
  }

  res.json(users);
});

// Handle undefined routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Route not found'
  });
});

// Global error handling middleware
app.use((err, req, res, next) => {
  console.error('Server error:', err);

  // Hide internal details in production
  const isProd = process.env.NODE_ENV === 'production';
  res.status(500).json({
    error: isProd ? 'Internal server error' : err.message
  });
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});

module.exports = app;

