// Test script to verify credentials and connectivity
require('dotenv').config({ path: '.env.test' });

const { Client } = require('pg');
const https = require('https');

async function testDatabaseConnection() {
  console.log('\nTesting database connection...');

  try {
    const client = new Client({
      connectionString: process.env.DATABASE_URL,
      ssl: false // Disable SSL for testing internal DB
    });

    await client.connect();
    const result = await client.query('SELECT NOW()');
    console.log('✅ Database connection: SUCCESS');
    console.log('Timestamp:', result.rows[0].now);
    await client.end();
  } catch (error) {
    console.log('❌ Database connection: FAILED');
    console.log('Error:', error.message);
  }
}

function testApiKey(url, apiKey, name) {
  return new Promise((resolve) => {
    console.log(`\nTesting ${name} API key...`);

    const options = {
      method: 'GET',
      headers: {
        'Content-Type': 'application/json',
      }
    };

    // Add authentication header based on service
    if (name === 'Anthropic') {
      options.headers['x-api-key'] = apiKey;
    } else if (name === 'Stripe') {
      options.auth = `${apiKey}:`;
    }

    const request = https.get(url, options, (response) => {
      let data = '';
      response.on('data', (chunk) => {
        data += chunk;
      });

      response.on('end', () => {
        if (response.statusCode === 200 || response.statusCode === 401) {
          // 401 means the API key was received but rejected - service is reachable
          // 200 means success (if we had valid permissions)
          console.log(`✅ ${name} API endpoint: REACHABLE`);
          if (response.statusCode === 401) {
            console.log(`⚠️  ${name} API key: INVALID (but service is reachable)`);
          }
        } else {
          console.log(`❌ ${name} API: FAILED - Status: ${response.statusCode}`);
        }
        resolve();
      });
    });

    request.on('error', (error) => {
      console.log(`❌ ${name} API: FAILED - Network error: ${error.message}`);
      resolve();
    });

    // Set timeout
    request.setTimeout(10000, () => {
      request.destroy();
      console.log(`❌ ${name} API: FAILED - Timeout`);
      resolve();
    });
  });
}

async function main() {
  console.log('Starting credential validation tests...');

  // Test database connection
  await testDatabaseConnection();

  // Test API keys
  if (process.env.ANTHROPIC_API_KEY) {
    await testApiKey('https://api.anthropic.com/v1/messages?max_tokens=1&messages[0][role]=user&messages[0][content]=hi&model=claude-2', 
                    process.env.ANTHROPIC_API_KEY, 'Anthropic');
  }

  if (process.env.STRIPE_SECRET_KEY) {
    await testApiKey('https://api.stripe.com/v1/account', 
                    process.env.STRIPE_SECRET_KEY, 'Stripe');
  }

  console.log('\nTests completed!\n');
}

main().catch(console.error);

