const app = express();

// Security middleware
app.use(helmet()); // Security headers
class RateLimiter {
  constructor(windowMs, maxRequests) {
    this.windowMs = windowMs;
    this.maxRequests = maxRequests;
    this.requests = new Map();
  }

  check(ip) {
    const now = Date.now();
    const windowStart = now - this.windowMs;

    // Clean old requests
    if (this.requests.has(ip)) {
      const requests = this.requests.get(ip).filter(timestamp => timestamp > windowStart);
      this.requests.set(ip, requests);
    }

    // Check if rate limited
    if (this.requests.has(ip) && this.requests.get(ip).length >= this.maxRequests) {
      return false;
    }

    // Add current request
    if (!this.requests.has(ip)) {
      this.requests.set(ip, []);
    }
    this.requests.get(ip).push(now);

    return true;
  }
}

const limiter = new RateLimiter(15 * 60 * 1000, 100); // 100 requests per 15 minutes

app.use((req, res, next) => {
  const ip = req.ip || req.connection.remoteAddress;
  if (limiter.check(ip)) {
    next();
