    await client.end().catch(() => {});
  }
}

// Generic HTTP request function to test API endpoints
function testApi(url, apiKeyHeader, apiKey) {
  return new Promise((resolve) => {
    if (!apiKey) {
      console.log(`❌ ${apiKeyHeader} not found in .env.test`);
      resolve(false);
      return;
    }

    const options = {
      headers: {
        'User-Agent': 'credential-verifier/1.0',
        [apiKeyHeader]: apiKey
      },
      timeout: 5000
    };

    const request = (url.startsWith('https:') ? https : http).request(url, options, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 200 && res.statusCode < 300) {
          console.log(`✅ ${apiKeyHeader.replace('-Key', '')} verified successfully`);
          resolve(true);
        } else {
          console.log(`❌ ${apiKeyHeader.replace('-Key', '')} failed with status: ${res.statusCode}`);
