    request.on('error', (error) => {
      console.log(`❌ ${apiKeyHeader.replace('-Key', '')} request failed:`, error.message);
      resolve(false);
    });

    request.on('timeout', () => {
      console.log(`❌ ${apiKeyHeader.replace('-Key', '')} request timed out`);
