const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const cors = require('cors');
const xss = require('xss-clean');
const mongoSanitize = require('express-mongo-sanitize');

const app = express();

// Security middleware
app.use(helmet()); // Security headers
app.use(xss()); // XSS protection
app.use(mongoSanitize()); // NoSQL injection protection

// CORS configuration
const corsOptions = {
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['http://localhost:3000'],
  optionsSuccessStatus: 200
};
app.use(cors(corsOptions));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true, // Return rate limit info in the RateLimit-* headers
  legacyHeaders: false, // Disable the X-RateLimit-* headers
});

// Apply rate limiter to all requests
app.use(limiter);

// Request parsing with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Centralized error handling middleware
app.use((err, req, res, next) => {
  console.error('Error:', err);

  if (res.headersSent) {
    return next(err);
  }

  const statusCode = err.statusCode || 500;
  res.status(statusCode).json({
    status: 'error',
    message: process.env.NODE_ENV === 'production' 
      ? 'Internal server error'
      : err.message,
    timestamp: new Date().toISOString()
  });
});

// Health check with proper error handling
app.get('/health', (req, res, next) => {
  try {
    // Validate query parameters if any
    const allowedFields = ['detailed'];
    constqueryParams = Object.keys(req.query);

    for (const field of queryParams) {
      if (!allowedFields.includes(field)) {
        return res.status(400).json({
          status: 'error',
          message: `Invalid query parameter: ${field}`,
          timestamp: new Date().toISOString()
        });
      }
    }

    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString(),
      environment: process.env.NODE_ENV || 'development'
    });
  } catch (error) {
    error.statusCode = 500;
    next(error);
  }
});

// Users endpoint with input validation
app.get('/users', (req, res, next) => {
  try {
    // Input validation
    const { page = 1, limit = 10, sort = 'name' } = req.query;

    // Validate and sanitize input
    const pageInt = parseInt(page, 10);
    const limitInt = parseInt(limit, 10);

    if (isNaN(pageInt) || pageInt < 1) {
      return res.status(400).json({
        status: 'error',
        message: 'Page must be a positive integer',
        timestamp: new Date().toISOString()
      });
    }

    if (isNaN(limitInt) || limitInt < 1 || limitInt > 100) {
      return res.status(400).json({
        status: 'error',
        message: 'Limit must be a positive integer between 1 and 100',
        timestamp: new Date().toISOString()
      });
    }

    const validSortFields = ['name', 'email', 'id'];
    if (!validSortFields.includes(sort)) {
      return res.status(400).json({
        status: 'error',
        message: `Sort field must be one of: ${validSortFields.join(', ')}`,
        timestamp: new Date().toISOString()
      });
    }

    // Simulated user data (in real app, this would come from a database)
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Simple pagination and sorting
    const sortedUsers = [...users].sort((a, b) => {
      if (a[sort] < b[sort]) return -1;
      if (a[sort] > b[sort]) return 1;
      return 0;
    });

    const startIndex = (pageInt - 1) * limitInt;
    const paginatedUsers = sortedUsers.slice(startIndex, startIndex + limitInt);

    res.json({
      status: 'success',
      results: paginatedUsers.length,
      pagination: {
        currentPage: pageInt,
        totalPages: Math.ceil(users.length / limitInt),
        hasNext: pageInt < Math.ceil(users.length / limitInt),
        hasPrev: pageInt > 1
      },
      data: paginatedUsers,
      timestamp: new Date().toISOString()
    });

  } catch (error) {
    error.statusCode = 500;
    next(error);
  }
});

// 404 handler for undefined routes
app.all('*', (req, res, next) => {
  const error = new Error(`Can't find ${req.originalUrl} on this server!`);
  error.statusCode = 404;
  next(error);
});

// Server startup with error handling
const PORT = process.env.PORT || 3000;

const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT} in ${process.env.NODE_ENV || 'development'} mode`);
});

// Handle unhandled promise rejections
process.on('unhandledRejection', (err) => {
  console.error('UNHANDLED REJECTION! 💥 Shutting down...');
  console.error(err.name, err.message);

  server.close(() => {
    process.exit(1);
  });
});

// Handle uncaught exceptions
process.on('uncaughtException', (err) => {
  console.error('UNCAUGHT EXCEPTION! 💥 Shutting down...');
  console.error(err.name, err.message);

  process.exit(1);
});

module.exports = app;

