// Simple rate limiting using in-memory store
const requestCounts = new Map();
const WINDOW_MS = 15 * 60 * 1000; // 15 minutes
const MAX_REQUESTS = 100; // Max requests per window

app.use((req, res, next) => {
  const clientIP = req.ip;
  const now = Date.now();
  const requestTime = now - WINDOW_MS;

  // Clean up old records
  for (const [ip, timestamps] of requestCounts) {
    requestCounts.set(ip, timestamps.filter(timestamp => timestamp > requestTime));
  }

  // Get or create request timestamps for this IP
  if (!requestCounts.has(clientIP)) {
    requestCounts.set(clientIP, []);
  }

  const clientRequests = requestCounts.get(clientIP);

  // Check if rate limit exceeded
  if (clientRequests.length >= MAX_REQUESTS) {
    return res.status(429).json({
      error: 'Too many requests from this IP, please try again later.'
    });
  }

  // Add current request timestamp
  clientRequests.push(now);
  requestCounts.set(clientIP, clientRequests);

  next();
});

