const requestCounts = new Map();
const RATE_LIMIT_WINDOW = 15 * 60 * 1000; // 15 minutes
const MAX_REQUESTS = 100;

app.use((req, res, next) => {
  const clientIP = req.ip || 'unknown';
  const now = Date.now();

  // Clean old entries
  if (requestCounts.size > 1000) {
    // Simple cleanup if we have too many entries
    const cleanupTime = now - RATE_LIMIT_WINDOW * 2;
    for (const [ip, data] of requestCounts) {
      if (data.timestamp < cleanupTime) {
        requestCounts.delete(ip);
      }
    }
  }

  const clientData = requestCounts.get(clientIP) || { count: 0, timestamp: now };

  // Reset counter if outside time window
  if (now - clientData.timestamp > RATE_LIMIT_WINDOW) {
    clientData.count = 0;
    clientData.timestamp = now;
  }

  clientData.count++;
  requestCounts.set(clientIP, clientData);

  // Check if rate limit exceeded
  if (clientData.count > MAX_REQUESTS) {
    return res.status(429).json({
      error: 'Too many requests from this IP, please try again later.',
      retryAfter: RATE_LIMIT_WINDOW - (now - clientData.timestamp)
    });
  }

