require('dotenv').config();
const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');
const { body, validationResult } = require('express-validator');
const winston = require('winston');

// Configure logging
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  defaultMeta: { service: 'user-service' },
  transports: [
    new winston.transports.File({ filename: 'error.log', level: 'error' }),
    new winston.transports.File({ filename: 'combined.log' })
  ]
});

// If we're not in production, log to the console as well
if (process.env.NODE_ENV !== 'production') {
  logger.add(new winston.transports.Console({
    format: winston.format.simple()
  }));
}

const app = express();

// Security middleware
app.use(helmet());

// CORS configuration
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS || 'https://trusted-domain.com',
  credentials: true
}));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100 // limit each IP to 100 requests per windowMs
});

app.use(limiter);

// Body parser
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Input validation middleware for user search
const validateUserQuery = [
  (req, res, next) => {
    try {
      // Sanitize query parameters
      if (req.query.name) {
        req.query.name = req.query.name.toString().trim().substring(0, 100);
      }
      if (req.query.email) {
        req.query.email = req.query.email.toString().trim().substring(0, 255);
      }
      next();
    } catch (error) {
      logger.error('Sanitization error:', error);
      return res.status(400).json({ error: 'Invalid request parameters' });
    }
  }
];

app.get('/health', [
  (req, res) => {
    // Log health check access
    logger.info('Health check endpoint accessed', {
      ip: req.ip,
      userAgent: req.get('User-Agent')
    });

    try {
      res.json({ status: 'ok', timestamp: new Date().toISOString() });
    } catch (error) {
      logger.error('Health check error:', error);
      res.status(500).json({ error: 'Health check failed' });
    }
  }
]);

app.get('/users', validateUserQuery, (req, res) => {
  try {
    // Log user access
    logger.info('Users endpoint accessed', {
      ip: req.ip,
      userAgent: req.get('User-Agent'),
      query: req.query
    });

    let users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Filter users by name if provided
    if (req.query.name) {
      const searchTerm = req.query.name.toLowerCase();
      users = users.filter(user => 
        user.name.toLowerCase().includes(searchTerm)
      );
    }

    // Filter users by email if provided
    if (req.query.email) {
      const searchTerm = req.query.email.toLowerCase();
      users = users.filter(user => 
        user.email.toLowerCase().includes(searchTerm)
      );
    }

    res.json(users);
  } catch (error) {
    logger.error('Users endpoint error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Error handling middleware
app.use((err, req, res, next) => {
  logger.error('Unhandled error:', {
    error: err.message,
    stack: err.stack,
    url: req.url,
    method: req.method,
    ip: req.ip
  });

  // Don't expose internal error details in production
  const errorResponse = {
    error: 'Internal server error'
  };

  if (process.env.NODE_ENV === 'development') {
    errorResponse.details = err.message;
    errorResponse.stack = err.stack;
  }

  res.status(500).json(errorResponse);
});

// 404 handler
app.use('*', (req, res) => {
  logger.warn('404 endpoint not found', {
    url: req.url,
    method: req.method,
    ip: req.ip
  });
  res.status(404).json({ error: 'Endpoint not found' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  logger.info(`Server running on port ${PORT}`);
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

