const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');
const sanitize = require('express-mongo-sanitize');

const app = express();

// Security middleware
app.use(helmet()); // Security headers

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
});
app.use('/api/', limiter);

// CORS configuration
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS ? process.env.ALLOWED_ORIGINS.split(',') : false,
  credentials: true,
}));

// Body parsing with size limits
app.use(express.json({
  limit: '10kb',
  type: ['application/json'],
}));

// Input sanitization
app.use(sanitize({
  replaceWith: '_',
}));

// Health check with minimal information disclosure
app.get('/health', (req, res) => {
  // Log request but don't expose system details
  console.log(`Health check requested at ${new Date().toISOString()}`);

  res.json({ 
    status: 'ok', 
    timestamp: new Date().toISOString() 
  });
});

// Users route with input validation
app.get('/users', (req, res) => {
  try {
    // Validate query parameters if present
    const { limit, offset, search } = req.query;

    let validatedLimit = 10;
    let validatedOffset = 0;

    if (limit !== undefined) {
      const parsedLimit = parseInt(limit, 10);
      if (isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 100) {
        return res.status(400).json({
          error: 'Invalid limit parameter. Must be between 1 and 100.',
        });
      }
      validatedLimit = parsedLimit;
    }

    if (offset !== undefined) {
      const parsedOffset = parseInt(offset, 10);
      if (isNaN(parsedOffset) || parsedOffset < 0) {
        return res.status(400).json({
          error: 'Invalid offset parameter. Must be a non-negative integer.',
        });
      }
      validatedOffset = parsedOffset;
    }

    // Mock data - in real app, this would come from a database
    const mockUsers = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
      { id: 3, name: 'Charlie', email: 'charlie@example.com' },
    ];

    // Filter by search if provided
    let filteredUsers = mockUsers;
    if (search && typeof search === 'string') {
      const searchTerm = search.trim().toLowerCase();
      if (searchTerm.length > 0) {
        if (searchTerm.length < 2) {
          return res.status(400).json({
            error: 'Search term must be at least 2 characters long.',
          });
        }
        filteredUsers = mockUsers.filter(user => 
          user.name.toLowerCase().includes(searchTerm) || 
          user.email.toLowerCase().includes(searchTerm)
        );
      }
    }

    // Apply pagination
    const paginatedUsers = filteredUsers.slice(validatedOffset, validatedOffset + validatedLimit);

    res.json({
      users: paginatedUsers,
      total: filteredUsers.length,
      limit: validatedLimit,
      offset: validatedOffset,
    });

  } catch (error) {
    console.error('Error processing users request:', error);
    res.status(500).json({
      error: 'Internal server error',
    });
  }
});

// 404 handler for unknown routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: 'Route not found',
  });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Unhandled error:', error);

  res.status(500).json({
    error: 'Internal server error',
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

