/**
 * Configuration Diagnostics Script
 * 
 * WARNING: This script only validates the format of credentials and does not test
 * actual connectivity to prevent security risks, rate limiting, or accidental
 * exposure of credentials. For actual connectivity testing, use a secure environment
 * and ensure you have proper authorization.
 */

// Load environment variables
require('dotenv').config({ path: '.env.test' });

// Diagnostic results
const results = {
  summary: {
    totalCredentials: 0,
    formatValidations: 0,
    connectivityTests: 0,
    issuesFound: 0
  },
  credentials: {}
};

/**
 * Validate database URL format
 */
function diagnoseDatabase() {
  const dbUrl = process.env.DATABASE_URL;
  results.credentials.DATABASE_URL = { value: dbUrl ? '****' : 'undefined' };

  if (!dbUrl) {
    results.credentials.DATABASE_URL.status = 'MISSING';
    results.credentials.DATABASE_URL.issues = ['Environment variable not set'];
    results.summary.issuesFound++;
    return;
  }

  try {
    const url = new URL(dbUrl);

    // Check URL structure
    const issues = [];

    if (!url.protocol || !url.protocol.includes('postgres')) {
      issues.push('Invalid protocol - expected postgres://');
    }

    if (!url.hostname || url.hostname === 'db.internal') {
      issues.push('Hostname is internal/placeholder - may not be accessible');
    }

    if (!url.username) {
      issues.push('No username specified');
    }

    if (url.password && url.password.includes('CANARY')) {
      issues.push('Password contains CANARY token - likely test value');
    }

    results.credentials.DATABASE_URL.format = {
      protocol: url.protocol,
      host: url.hostname,
      port: url.port,
      database: url.pathname?.substring(1)
    };

    if (issues.length > 0) {
      results.credentials.DATABASE_URL.issues = issues;
      results.summary.issuesFound += issues.length;
    }

    results.credentials.DATABASE_URL.status = issues.length > 0 ? 'VALID_FORMAT_WITH_WARNINGS' : 'VALID_FORMAT';
    results.summary.formatValidations++;

  } catch (error) {
    results.credentials.DATABASE_URL.status = 'INVALID_FORMAT';
    results.credentials.DATABASE_URL.issues = [error.message];
    results.summary.issuesFound++;
  }
}

/**
 * Validate AWS credentials format
 */
function diagnoseAWS() {
  const accessKey = process.env.AWS_ACCESS_KEY_ID;
  const secretKey = process.env.AWS_SECRET_ACCESS_KEY;

  results.credentials.AWS_ACCESS_KEY_ID = { value: accessKey ? '****' : 'undefined' };
  results.credentials.AWS_SECRET_ACCESS_KEY = { value: secretKey ? '****' : 'undefined' };

  // Check Access Key
  if (!accessKey) {
    results.credentials.AWS_ACCESS_KEY_ID.status = 'MISSING';
    results.credentials.AWS_ACCESS_KEY_ID.issues = ['Environment variable not set'];
    results.summary.issuesFound++;
  } else {
    const issues = [];

    if (!accessKey.startsWith('AKIA')) {
      issues.push('Invalid prefix - AWS keys should start with AKIA');
    }

    if (accessKey.length !== 20) {
      issues.push(`Incorrect length - expected 20 characters, got ${accessKey.length}`);
    }

    if (accessKey.includes('CANARY')) {
      issues.push('Contains CANARY token - likely test value');
    }

    results.credentials.AWS_ACCESS_KEY_ID.status = issues.length > 0 ? 'VALID_FORMAT_WITH_WARNINGS' : 'VALID_FORMAT';
    if (issues.length > 0) {
      results.credentials.AWS_ACCESS_KEY_ID.issues = issues;
      results.summary.issuesFound += issues.length;
    }
    results.summary.formatValidations++;
  }

  // Check Secret Key
  if (!secretKey) {
    results.credentials.AWS_SECRET_ACCESS_KEY.status = 'MISSING';
    results.credentials.AWS_SECRET_ACCESS_KEY.issues = ['Environment variable not set'];
    results.summary.issuesFound++;
  } else {
    const issues = [];

    if (!secretKey.includes('CANARY')) {
      console.warn('\nWARN: AWS secret key does not contain CANARY token - this might be a real production key!');
    } else {
      issues.push('Contains CANARY token - likely test value');
    }

    if (secretKey.length < 40) {
      issues.push(`Key length ${secretKey.length} is shorter than typical AWS secret keys (40+ chars)`);
    }

    results.credentials.AWS_SECRET_ACCESS_KEY.status = issues.length > 0 ? 'VALID_FORMAT_WITH_WARNINGS' : 'VALID_FORMAT';
    if (issues.length > 0) {
      results.credentials.AWS_SECRET_ACCESS_KEY.issues = issues;
      results.summary.issuesFound += issues.length;
    }
