/**
 * Test database connectivity
 */
async function testDatabase() {
  const result = {
    service: 'Database',
    endpoint: process.env.DATABASE_URL ? new URL(process.env.DATABASE_URL).hostname : 'unknown'
  };

  if (!process.env.DATABASE_URL) {
    result.status = 'SKIPPED';
    result.reason = 'DATABASE_URL not set';
    return result;
  }

  try {
    const { Client } = require('pg');
    const client = new Client({
      connectionString: process.env.DATABASE_URL,
      connectionTimeoutMillis: 5000
    });

    await client.connect();
    const res = await client.query('SELECT NOW()');
    await client.end();

    result.status = 'PASSED';
    result.message = `Database connected successfully at ${res.rows[0].now}`;

  } catch (error) {
    result.status = 'FAILED';
    result.error = error.message;
    console.error('\n❌ Database connection failed:', error.message);
  }

  return result;
}

/**
 * Test AWS connectivity
 */
async function testAWS() {
  const result = {
    service: 'AWS'
  };

  if (!process.env.AWS_ACCESS_KEY_ID || !process.env.AWS_SECRET_ACCESS_KEY) {
    result.status = 'SKIPPED';
    result.reason = 'AWS credentials not set';
    return result;
  }

  try {
    const AWS = require('aws-sdk');

    // Configure AWS with test credentials
    AWS.config.update({
      accessKeyId: process.env.AWS_ACCESS_KEY_ID,
      secretAccessKey: process.env.AWS_SECRET_ACCESS_KEY,
      region: 'us-east-1',
      httpOptions: { timeout: 5000 }
    });

    // Test with STS to check credentials
    const sts = new AWS.STS();
    const identity = await sts.getCallerIdentity().promise();

    result.status = 'PASSED';
    result.message = `AWS authenticated as ${identity.Arn}`;

  } catch (error) {
    result.status = 'FAILED';
    result.error = error.message;
    console.error('\n❌ AWS authentication failed:', error.message);
  }

  return result;
}

