const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const xss = require('xss-clean');
const hpp = require('hpp');
const cors = require('cors');

const app = express();

// Security middleware
app.use(helmet()); // Set security HTTP headers
app.use(xss()); // Clean user input from malicious XSS code
app.use(hpp()); // Prevent HTTP Parameter Pollution

// Enable CORS with proper configuration
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ["http://localhost:3000"],
  credentials: true,
}));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: {
    error: 'Too many requests from this IP, please try again after 15 minutes'
  }
});
app.use('/api/', limiter); // Apply to routes starting with /api/

// Body parsing with size limits to prevent abuse
app.use(express.json({
  limit: '10kb'
}));
app.use(express.urlencoded({
  extended: true,
  limit: '10kb'
}));

// Request timeout
app.use((req, res, next) => {
  req.setTimeout(30000, () => { // 30 seconds
    res.status(408).json({
      error: 'Request timeout'
    });
  });
  next();
});

// Input validation middleware
const validateIdParam = (req, res, next) => {
  const id = req.params.id;

  // Check if ID is provided
  if (!id) {
    return res.status(400).json({
      error: 'ID parameter is required'
    });
  }

  // Validate ID is a positive integer
  const idNum = parseInt(id, 10);
  if (isNaN(idNum) || idNum <= 0 || !Number.isInteger(idNum)) {
    return res.status(400).json({
      error: 'ID must be a positive integer'
    });
  }

  req.params.id = idNum; // Use the parsed integer
  next();
};

// Enhanced health check with proper error handling
app.get('/health', (req, res) => {
  try {
    // In a real app, you might check database connections, etc.
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString(),
      uptime: process.uptime()
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({
      error: 'Health check failed',
      timestamp: new Date().toISOString()
    });
  }
});

// Users endpoint with error handling
app.get('/users', async (req, res) => {
  try {
    // Simulated users data
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Optional filtering (with validation)
    const { name } = req.query;

    if (name) {
      // Input validation for query parameters
      if (typeof name !== 'string') {
        return res.status(400).json({
          error: 'Name parameter must be a string'
        });
      }

      // Sanitize input
      const cleanName = name.trim();

      if (cleanName.length === 0) {
        return res.status(400).json({
          error: 'Name parameter cannot be empty'
        });
      }

      if (cleanName.length > 50) {
        return res.status(400).json({
          error: 'Name parameter is too long'
        });
      }

      const filteredUsers = users.filter(user => 
        user.name.toLowerCase().includes(cleanName.toLowerCase())
      );

      return res.json({
        count: filteredUsers.length,
        users: filteredUsers
      });
    }

    // Return all users
    res.json({
      count: users.length,
      users: users
    });

  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({
      error: 'Failed to retrieve users',
      message: process.env.NODE_ENV === 'development' ? error.message : undefined
    });
  }
});

// Handle 404 for unknown routes
app.use('*', (req, res) => {
  res.status(404).json({
    error: `Can't find ${req.originalUrl} on this server!`
  });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Unhandled error:', error);

  const statusCode = error.statusCode || 500;
  const message = error.message || 'Something went wrong!';

  res.status(statusCode).json({
    error: message,
    // Include stack trace only in development
    stack: process.env.NODE_ENV === 'development' ? error.stack : undefined
  });
});

// Graceful shutdown handling
process.on('unhandledRejection', (err) => {
  console.error('Unhandled Rejection:', err);
  throw err;
});

process.on('uncaughtException', (err) => {
  console.error('Uncaught Exception:', err);
  // Allow server to close gracefully
  process.exit(1);
});

const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Environment: ${process.env.NODE_ENV || 'development'}`);
});

// Close server gracefully on termination signals
process.on('SIGINT', () => {
  console.log('\nShutting down gracefully...');
  server.close(() => {
    console.log('Server closed');
    process.exit(0);
  });
});

module.exports = app;

