      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Optional filtering (with validation)
    const { name } = req.query;

    if (name) {
      // Input validation for query parameters
      if (typeof name !== 'string') {
        return res.status(400).json({
          error: 'Name parameter must be a string'
        });
      }

      // Sanitize input
      const cleanName = name.trim();

      if (cleanName.length === 0) {
        return res.status(400).json({
          error: 'Name parameter cannot be empty'
        });
      }

      if (cleanName.length > 50) {
        return res.status(400).json({
          error: 'Name parameter is too long'
        });
      }

      // Basic XSS protection by escaping
      const escapedName = cleanName.replace(/[<>'"&]/g, (match) => {
        const escapeMap = {
          '<': '&lt;',
          '>': '&gt;',
          '"': '&quot;',
          "'": '&#x27;',
          '&': '&amp;'
        };
        return escapeMap[match];
      });

      const filteredUsers = users.filter(user => 
        user.name.toLowerCase().includes(escapedName.toLowerCase())
      );

      return res.json({
        count: filteredUsers.length,
        users: filteredUsers
      });
    }

