const express = require('express');

const app = express();

// Basic security headers (without helmet)
app.use((req, res, next) => {
  // Prevent MIME type sniffing
  res.setHeader('X-Content-Type-Options', 'nosniff');

  // Prevent page from being displayed in iframe
  res.setHeader('X-Frame-Options', 'DENY');

  // Enable XSS protection
  res.setHeader('X-XSS-Protection', '1; mode=block');

  // Disable caching for security-sensitive applications
  res.setHeader('Cache-Control', 'no-cache, no-store, must-revalidate');
  res.setHeader('Pragma', 'no-cache');
  res.setHeader('Expires', '0');

  // Set content security policy (basic)
  res.setHeader('Content-Security-Policy', "default-src 'self'; frame-ancestors 'none'; form-action 'self'");

  next();
});

// Set timeout for requests
app.use((req, res, next) => {
  req.setTimeout(30000); // 30 seconds
  res.setTimeout(30000, () => {
    console.log('Request timed out');
    res.status(408).send('Request timeout');
  });
  next();
});

// Enhanced health check with error handling
app.get('/health', (req, res) => {
  try {
    // Add any actual health checks here (database, external services, etc.)
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString() 
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(503).json({ 
      status: 'error', 
      message: 'Service unavailable',
      timestamp: new Date().toISOString() 
    });
  }
});

// Users endpoint with input validation (for future query parameters)
app.get('/users', (req, res) => {
  try {
    // Example input validation if query parameters were used
    if (req.query.page !== undefined) {
      const page = parseInt(req.query.page);
      if (isNaN(page) || page < 1) {
        return res.status(400).json({
          error: 'Invalid query parameters',
          message: 'Page must be a positive integer'
        });
      }
    }

    if (req.query.limit !== undefined) {
      const limit = parseInt(req.query.limit);
      if (isNaN(limit) || limit < 1 || limit > 100) {
        return res.status(400).json({
          error: 'Invalid query parameters',
          message: 'Limit must be a positive integer and cannot exceed 100'
        });
      }
    }

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.json(users);
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({
      error: 'Internal server error',
      message: 'Failed to fetch users'
    });
  }
});

// Handle requests with potentially dangerous methods
app.use((req, res, next) => {
  // Sanitize request headers
  Object.keys(req.headers).forEach(header => {
    if (header.toLowerCase().includes('x-') || header.toLowerCase().includes('csrf')) {
      // Log suspicious headers but allow processing to continue
      console.log(`Suspicious header received: ${header}`);
    }
  });
