  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');

  // Limit request body size
  if (req.method === 'POST' || req.method === 'PUT' || req.method === 'PATCH') {
    req.setMaxListeners(1024);
  }

  next();
});

// Input validation middleware
const validateQueryParams = (req, res, next) => {
  // Reject queries with too many parameters (potential abuse)
  const paramCount = Object.keys(req.query).length;
  if (paramCount > 10) {
    return res.status(400).json({
      error: 'Too many query parameters'
    });
  }

  // Validate parameter names and values
  for (const [key, value] of Object.entries(req.query)) {
    // Check for common attack patterns
    if (typeof value === 'string' && (
      value.includes('<script') || 
      value.includes('javascript:') ||
      value.includes('data:') ||
      value.includes('vbscript:')
    )) {
      return res.status(400).json({
        error: 'Invalid parameter value'
      });
    }

    // Add specific validation based on expected parameters
    if (key === 'id' && value && isNaN(parseInt(value))) {
      return res.status(400).json({
        error: 'ID must be a number'
      });
    }

    if (key === 'page' && value && isNaN(parseInt(value))) {
      return res.status(400).json({
        error: 'Page must be a number'
      });
    }
  }

  next();
};

