    // Add basic rate limiting by tracking recent requests in memory
    // In production, use Redis or similar for distributed rate limiting
    if (!global.rateLimitStore) {
      global.rateLimitStore = {};
    }

    const ip = req.ip || 'unknown';
    const now = Date.now();
    const windowMs = 15 * 60 * 1000; // 15 minutes

    // Clean up old entries
    Object.keys(global.rateLimitStore).forEach(key => {
      if (now - global.rateLimitStore[key].timestamp > windowMs) {
        delete global.rateLimitStore[key];
      }
    });

    // Check rate limit
    if (global.rateLimitStore[ip] && 
        global.rateLimitStore[ip].count >= 100 &&
        now - global.rateLimitStore[ip].timestamp < windowMs) {
      return res.status(429).json({
        error: 'Too many requests, please try again later'
      });
    }

    // Update rate limit counter
    if (!global.rateLimitStore[ip]) {
      global.rateLimitStore[ip] = { count: 0, timestamp: now };
