          error: 'Name parameter must be between 1 and 50 characters'
        });
      }

      // Prevent potential regex injection by escaping special characters
      const safeName = name.replace(/[.*+?^${}()|[\]]/g, '\$&');
      const regex = new RegExp(safeName, 'i');

      filteredUsers = filteredUsers.filter(user => 
