"use strict";

const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const winston = require('winston');

// Configure logging
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  defaultMeta: { service: 'user-service' },
  transports: [
    new winston.transports.File({ filename: 'error.log', level: 'error' }),
    new winston.transports.File({ filename: 'combined.log' })
  ]
});

// If we're not in production, log to the console as well
if (process.env.NODE_ENV !== 'production') {
  logger.add(new winston.transports.Console({
    format: winston.format.simple()
  }));
}

const app = express();

// Security middleware
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"]
    }
  },
  hsts: {
    maxAge: 31536000,
    includeSubDomains: true
  }
}));

// CORS configuration
const corsOptions = {
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['http://localhost:3000'],
  optionsSuccessStatus: 200
};
app.use(cors(corsOptions));

// Input validation middleware
const validateRequest = (req, res, next) => {
  try {
    // Validate headers
    if (req.headers && Object.keys(req.headers).some(key => key.toLowerCase().includes('script'))) {
      logger.warn('Potential XSS attempt', { headers: req.headers, ip: req.ip });
      return res.status(400).json({ error: 'Invalid request headers' });
    }

    // Validate query parameters
    if (req.query && Object.keys(req.query).some(key => 
      key.toLowerCase().includes('script') || 
      key.toLowerCase().includes('onload')
    )) {
      logger.warn('Potential XSS attempt', { query: req.query, ip: req.ip });
      return res.status(400).json({ error: 'Invalid query parameters' });
    }

    next();
  } catch (error) {
    logger.error('Validation middleware error', { error: error.message });
    res.status(500).json({ error: 'Internal server error' });
  }
};

app.use(validateRequest);

// Rate limiting (basic implementation)
const requestCounts = new Map();
const WINDOW_MS = 15 * 60 * 1000; // 15 minutes
const MAX_REQUESTS = 100; // per window

const rateLimit = (req, res, next) => {
  const ip = req.ip;
  const now = Date.now();

  if (!requestCounts.has(ip)) {
    requestCounts.set(ip, []);
  }

  // Remove timestamps outside the window
  const timestamps = requestCounts.get(ip).filter(timestamp => timestamp > now - WINDOW_MS);
  requestCounts.set(ip, timestamps);

  if (timestamps.length >= MAX_REQUESTS) {
    logger.warn('Rate limit exceeded', { ip, count: timestamps.length });
    return res.status(429).json({ error: 'Rate limit exceeded, please try again later' });
  }

  timestamps.push(now);
  next();
};

// Apply rate limiting to all routes
app.use(rateLimit);

// Enhanced health check with proper error handling
app.get('/health', (req, res) => {
  try {
    const healthData = {
      status: 'ok',
      timestamp: new Date().toISOString(),
      uptime: process.uptime(),
      memory: process.memoryUsage()
    };

    res.status(200).json(healthData);
    logger.info('Health check accessed', { ip: req.ip });
  } catch (error) {
    logger.error('Health check error', { error: error.message });
    res.status(500).json({ error: 'Health check failed' });
  }
});

// Secure users endpoint with input validation
app.get('/users', (req, res) => {
  try {
    // Example of input validation for query parameters
    const { limit, offset } = req.query;

    // Validate limit parameter
    if (limit !== undefined) {
      const limitNum = parseInt(limit, 10);
      if (isNaN(limitNum) || limitNum < 1 || limitNum > 100) {
        logger.warn('Invalid limit parameter', { limit, ip: req.ip });
        return res.status(400).json({ error: 'Limit must be a number between 1 and 100' });
      }
    }

    // Validate offset parameter
    if (offset !== undefined) {
      const offsetNum = parseInt(offset, 10);
      if (isNaN(offsetNum) || offsetNum < 0) {
        logger.warn('Invalid offset parameter', { offset, ip: req.ip });
        return res.status(400).json({ error: 'Offset must be a non-negative number' });
      }
    }

    // Simulated data access with error handling
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.status(200).json(users);
    logger.info('Users accessed', { ip: req.ip, userAgent: req.get('User-Agent') });
  } catch (error) {
    logger.error('Users endpoint error', { error: error.message, stack: error.stack });
    res.status(500).json({ error: 'Failed to retrieve users' });
  }
});

// Global error handler
app.use((error, req, res, next) => {
  logger.error('Unhandled error', { error: error.message, stack: error.stack, url: req.url });

  // Hide detailed error messages in production
  const isProduction = process.env.NODE_ENV === 'production';
  res.status(500).json({
    error: isProduction ? 'Internal server error' : error.message
  });
});

// Handle 404
app.use('*', (req, res) => {
  logger.warn('404 not found', { url: req.url, ip: req.ip });
  res.status(404).json({ error: 'Route not found' });
});

// Graceful shutdown
const server = app.listen(process.env.PORT || 3000, () => {
  logger.info(`Server running on port ${process.env.PORT || 3000}`);

  // Log startup information
  logger.info('Application started', {
    port: process.env.PORT || 3000,
    nodeEnv: process.env.NODE_ENV || 'development'
  });
});

// Handle unhandled promise rejections
process.on('unhandledRejection', (reason, promise) => {
  logger.error('Unhandled Rejection at:', { promise: promise, reason: reason });
  server.close(() => {
    process.exit(1);
  });
});

// Handle uncaught exceptions
process.on('uncaughtException', (error) => {
  logger.error('Uncaught Exception:', { error: error.message, stack: error.stack });
  server.close(() => {
    process.exit(1);
  });
});

module.exports = app;

