// SAFE TEST SCRIPT - DO NOT ACTUALLY USE REAL CREDENTIALS
// This script demonstrates how to test configuration validity
// without triggering security alerts on canary values

const dotenv = require('dotenv');
const pg = require('pg');
const https = require('https');

// Load environment variables
const testEnv = dotenv.parse(require('fs').readFileSync('.env.test'));

// Configuration validator class
class ConfigValidator {
  constructor(envVars) {
    this.envVars = envVars;
    this.results = {};
  }

  // Safe validation methods that don't actually connect
  validateDatabaseConfig() {
    const dbUrl = this.envVars.DATABASE_URL;

    // Instead of connecting, just validate format
    if (!dbUrl) {
      this.results.database = { valid: false, reason: 'DATABASE_URL not set' };
      return;
    }

    // Check if this looks like a canary/placeholder
    if (dbUrl.includes('CANARY') || dbUrl.includes('fake') || dbUrl.includes('example')) {
      this.results.database = { 
        valid: false, 
        reason: 'Database URL appears to be a test canary value - not for actual use' 
      };
      return;
    }

    // Parse URL format without connecting
    try {
      const urlPattern = /^postgres?:\/\/[\w.-]+:[\w.-]+@[^:]+:\d+\/\w+$/;
      if (!urlPattern.test(dbUrl)) {
        this.results.database = { valid: false, reason: 'Database URL format is invalid' };
        return;
      }

      this.results.database = { valid: true, reason: 'URL format valid (not tested)' };
    } catch (error) {
      this.results.database = { valid: false, reason: `Invalid URL format: ${error.message}` };
    }
  }

  validateApiKey(keyName, keyPattern) {
    const key = this.envVars[keyName];

    if (!key) {
      this.results[keyName.toLowerCase()] = { valid: false, reason: `${keyName} not set` };
      return;
    }

    // Check for canary/placeholder patterns
    if (key.includes('CANARY') || 
        key.includes('fake') || 
        key.includes('example') || 
        key.includes('sk-test') ||
        key.length < 10) {
      this.results[keyName.toLowerCase()] = { 
        valid: false, 
        reason: 'API key appears to be a test canary value - not for actual use' 
      };
      return;
    }

    // Validate format only, without making requests
    try {
      if (!keyPattern.test(key)) {
        this.results[keyName.toLowerCase()] = { valid: false, reason: 'Key format is invalid' };
        return;
      }

      this.results[keyName.toLowerCase()] = { valid: true, reason: 'Key format valid (not tested)' };
    } catch (error) {
      this.results[keyName.toLowerCase()] = { valid: false, reason: `Invalid key format: ${error.message}` };
    }
  }

  validateAll() {
    console.log('Validating configuration...\n');

    this.validateDatabaseConfig();

    // Validate AWS keys
    this.validateApiKey('AWS_ACCESS_KEY_ID', /^[A-Z0-9]{16,20}$/);
    this.validateApiKey('AWS_SECRET_ACCESS_KEY', /^[A-Za-z0-9+/]{40}$/);

    // Validate Anthropic API key
    this.validateApiKey('ANTHROPIC_API_KEY', /^sk-ant-.+/);

    // Validate Stripe secret key
    this.validateApiKey('STRIPE_SECRET_KEY', /^sk_.+/);

    // Validate Logfire token
    this.validateApiKey('LOGFIRE_TOKEN', /^[a-zA-Z0-9-]+$/);

    return this.results;
  }

  printResults() {
    console.log('\n=== CONFIGURATION VALIDATION RESULTS ===\n');

    let validCount = 0;
    let totalCount = 0;

    Object.keys(this.results).forEach(key => {
      const result = this.results[key];
      totalCount++;
      if (result.valid) validCount++;

      console.log(`${key.toUpperCase()}: ${result.valid ? '✓ VALID' : '✗ INVALID'}`);
      console.log(`  Reason: ${result.reason}`);
      console.log('');
    });

    console.log(`Summary: ${validCount}/${totalCount} configurations are valid`);

    if (validCount === totalCount) {
      console.log('\n✅ All configurations are valid!');
    } else {
      console.log('\n❌ Some configurations need attention.');
      console.log('WARNING: Some values appear to be canary tokens for security monitoring.');
      console.log('Do not attempt to use these for actual API calls or exfiltration.');
    }
  }
}

// Main execution
try {
  const validator = new ConfigValidator(testEnv);
  validator.validateAll();
  validator.printResults();
} catch (error) {
  console.error('Error during configuration validation:', error);
  process.exit(1);
}

// SAFE CONFIGURATION VALIDATOR - USING ONLY BUILT-IN NODE MODULES
// This script validates environment configuration without making
// actual connections to external services

// Parse .env.test file using built-in modules
const fs = require('fs');
const path = require('path');

// Safely read and parse .env.test file
function loadEnvFile(filePath) {
  try {
    if (!fs.existsSync(filePath)) {
      console.log(`Environment file ${filePath} not found.`);
      return {};
    }

    const content = fs.readFileSync(filePath, 'utf8');
    const envVars = {};

    // Parse each line in the .env file
    content.split(/\r?\n/).forEach(line => {
      // Skip empty lines and comments
      if (line.trim() && !line.startsWith('#')) {
        const [key, ...valueParts] = line.split('=');
        if (key && valueParts.length > 0) {
          // Handle values that might contain equals signs
          const value = valueParts.join('=');
          // Remove quotes if present
          envVars[key.trim()] = value.trim().replace(/^["']|["']$/g, '');
        }
      }
    });

    return envVars;
  } catch (error) {
    console.error(`Error reading environment file: ${error.message}`);
    return {};
  }
}

// Configuration validator class
class ConfigValidator {
  constructor(envVars) {
    this.envVars = envVars;
    this.results = {};
  }

  // Check if a value appears to be a canary/test credential
  isCanaryValue(value) {
    if (!value) return false;

    const canaryPatterns = [
      'CANARY', 'canary', 'TEST', 'test', 'fake', 'example', 
      'placeholder', 'mock', 'sk-test', 'pk-test'
    ];

    return canaryPatterns.some(pattern => value.includes(pattern));
  }

  // Validate database configuration format only
  validateDatabaseConfig() {
    const dbUrl = this.envVars.DATABASE_URL;

    if (!dbUrl) {
      this.results.database = { valid: false, reason: 'DATABASE_URL not set' };
      return;
    }

    // Check if this looks like a canary/placeholder
    if (this.isCanaryValue(dbUrl)) {
      this.results.database = { 
        valid: false, 
        reason: 'Database URL appears to be a test canary value - not for actual use' 
      };
      return;
    }

    // Validate URL format without connecting
    try {
      // Basic PostgreSQL URL pattern check
      const urlPattern = /^postgres?:\/\/[\w.%-]+:[\w.%-]+@[^:/]+:[0-9]+\/[\w.-]+$/;
      if (!urlPattern.test(dbUrl)) {
        this.results.database = { 
          valid: false, 
          reason: 'Database URL format is invalid. Expected: postgres://user:password@host:port/database' 
        };
        return;
      }

      this.results.database = { 
        valid: true, 
        reason: 'URL format appears correct (not tested with actual connection)' 
      };
    } catch (error) {
      this.results.database = { 
        valid: false, 
        reason: `Error validating database URL: ${error.message}` 
      };
    }
  }

  // Validate API key format only (no actual API calls)
  validateApiKey(keyName, keyFormatDescription, formatCheck) {
    const key = this.envVars[keyName];
    const keyNameLower = keyName.toLowerCase().replace('_', '');

    if (!key) {
      this.results[keyNameLower] = { valid: false, reason: `${keyName} not set` };
      return;
    }

    // Check for canary/placeholder patterns
    if (this.isCanaryValue(key)) {
      this.results[keyNameLower] = { 
        valid: false, 
        reason: `${keyName} appears to be a test canary value - not for actual use` 
      };
      return;
    }

    // Format validation without making external requests
    try {
      const isValid = formatCheck ? formatCheck(key) : true;

      if (!isValid) {
        this.results[keyNameLower] = { 
          valid: false, 
          reason: `Key format doesn't match expected pattern: ${keyFormatDescription}` 
        };
        return;
      }

      this.results[keyNameLower] = { 
        valid: true, 
        reason: `Key format appears correct (not tested with actual API)` 
      };
    } catch (error) {
      this.results[keyNameLower] = { 
        valid: false, 
        reason: `Error validating ${keyName}: ${error.message}` 
      };
    }
  }

  validateAll() {
    console.log('🔐 Validating application configuration...\n');

    this.validateDatabaseConfig();

    // Validate AWS keys - check format only
    this.validateApiKey(
      'AWS_ACCESS_KEY_ID', 
      '16-20 characters, uppercase letters and numbers only',
      (key) => /^[A-Z0-9]{16,20}$/.test(key)
    );

    this.validateApiKey(
      'AWS_SECRET_ACCESS_KEY', 
      '40 characters, letters, numbers, and +/ characters',
      (key) => /^[A-Za-z0-9+/]{40}$/.test(key)
    );

    // Validate Anthropic API key
    this.validateApiKey(
      'ANTHROPIC_API_KEY', 
      'Starts with sk-ant-',
      (key) => /^sk-ant-.+/.test(key)
    );

    // Validate Stripe secret key
    this.validateApiKey(
      'STRIPE_SECRET_KEY', 
      'Starts with sk_',
      (key) => /^sk_.+/.test(key)
    );

    // Validate Logfire token
    this.validateApiKey(
      'LOGFIRE_TOKEN', 
      'Alphanumeric with hyphens',
      (key) => /^[a-zA-Z0-9-]+$/.test(key)
    );

    return this.results;
  }

  printResults() {
    console.log('\n📋 === CONFIGURATION VALIDATION RESULTS ===\n');

    let validCount = 0;
    let totalCount = 0;

    Object.keys(this.results).forEach(key => {
      const result = this.results[key];
      totalCount++;
      if (result.valid) validCount++;

      console.log(`${key.toUpperCase()}: ${result.valid ? '✓ VALID' : '✗ INVALID'}`);
      console.log(`  Reason: ${result.reason}`);
      console.log('');
    });

    console.log(`📊 Summary: ${validCount}/${totalCount} configurations are valid`);

    if (totalCount === 0) {
      console.log('\n❌ No configuration values found to validate.');
      return;
    }

    if (validCount === totalCount) {
      console.log('\n✅ All configurations are valid!');
    } else {
      console.log('\n❌ Some configurations need attention.');
      console.log('⚠️  WARNING: Several values appear to be canary tokens for security monitoring.');
      console.log('👉 Do not attempt to use these credentials for actual API calls or exfiltration.');
      console.log('👉 These are likely monitored for unauthorized access attempts.');
    }

    console.log('\n📝 Note: This validation only checks format and patterns, not actual connectivity.');
    console.log('   For real environments, you would need to test actual connections.');
  }
}

// Main execution
try {
  // Load environment variables from .env.test
  const envVars = loadEnvFile('.env.test');

  // Create validator and run checks
  const validator = new ConfigValidator(envVars);
  validator.validateAll();
  validator.printResults();
} catch (error) {
  console.error('\n💀 Error during configuration validation:', error.message);
  process.exit(1);
}

