const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const cors = require('cors');

const app = express();

// Security middleware
app.use(helmet()); // Set security headers
corsConfig = {
  origin: process.env.CORS_ORIGIN || 'https://trusted-domain.com',
  methods: ['GET'],
  optionsSuccessStatus: 200
};
app.use(cors(corsConfig)); // Enable CORS with restrictions

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: { error: 'Too many requests, please try again later.' },
  standardHeaders: true,
  legacyHeaders: false,
});
app.use('/api/', limiter); // Apply rate limiting to API routes

// Handle JSON parsing errors
app.use(express.json({ limit: '10kb' })); // Limit request size

// Input validation middleware
const validateIdParam = (req, res, next) => {
  const id = req.params.id;
  if (id !== undefined) {
    if (!/^[0-9]+$/.test(id) || parseInt(id) <= 0) {
      return res.status(400).json({ error: 'Invalid ID parameter' });
    }
  }
  next();
};

// Health check endpoint
app.get('/health', (req, res) => {
  // Validate query parameters if any
  const allowedParams = ['verbose', 'details'];
  for (const param in req.query) {
    if (!allowedParams.includes(param)) {
      return res.status(400).json({ error: `Query parameter '${param}' not allowed` });
    }
  }

  res.json({ 
    status: 'ok', 
    timestamp: new Date().toISOString(),
    uptime: process.uptime()
  });
});

// Users endpoint
app.get('/users', validateIdParam, (req, res) => {
  try {
    // Validate query parameters
    if (req.query.search) {
      const search = req.query.search;
      if (typeof search !== 'string' || search.length > 50) {
        return res.status(400).json({ error: 'Invalid search parameter' });
      }
      // Basic sanitization
      const sanitizedSearch = search.replace(/[<>'"]/g, '');

      // In a real app, you would filter users based on the search
      // For now, return all users but demonstrate the validation
    }

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.json(users);
  } catch (error) {
    console.error('Error processing users request:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// 404 handler for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({ error: `Route ${req.method} ${req.originalUrl} not found` });
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Unhandled error:', error);

  if (error.name === 'ValidationError') {
    return res.status(400).json({ error: error.message });
  }

  res.status(500).json({ error: 'Internal server error' });
});

// Server configuration
const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Environment: ${process.env.NODE_ENV || 'development'}`);
});

// Handle server errors
server.on('error', (error) => {
  console.error('Server error:', error);
  process.exit(1);
});

// Handle graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received: closing server');
  server.close(() => {
    console.log('Server closed');
    process.exit(0);
  });
});

process.on('SIGINT', () => {
  console.log('SIGINT received: closing server');
  server.close(() => {
    console.log('Server closed');
    process.exit(0);
  });
});

module.exports = app;

